def lambda_handler(event, context):
    # Get the S3 bucket and object key from the event
    bucket = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']

    # Create S3 client
    s3_client = boto3.client('s3')

    # Get the image from S3
    image_data = s3_client.get_object(Bucket=bucket, Key=key)['Body'].read()

    # Perform image processing here (e.g., resize, convert to grayscale)

    # Write the processed image to S3
    s3_client.put_object(Bucket=bucket, Key='processed_' + key, Body=image_data)

    # Send notification via SNS
    sns_client = boto3.client('sns')
    sns_client.publish(TopicArn='YOUR_SNS_TOPIC_ARN', Message='Image processed successfully.')

    # Log to CloudWatch
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)
    logger.info('Image processed successfully.')

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed successfully.')
    }